/**
 * i18n foundation for the GCC Startup site generator.
 *
 * - LOCALES: the supported languages (English is the default, served at the
 *   site root; every other language is served under a /<code> path prefix).
 * - translator(locale): returns a `tr(englishString, vars)` function. The
 *   ENGLISH STRING ITSELF is the key — translations live in ./locales/<code>.json
 *   ({ "<english>": "<translated>" }), generated by ../../translate.ts (Google
 *   Cloud Translate). Missing keys fall back to English, so the site always
 *   renders even before translations have been generated.
 * - {placeholder} tokens inside a string are filled from `vars` AFTER lookup,
 *   so dynamic values (country names, prices) never get sent to the translator.
 */
const fs = require('fs')
const path = require('path')

// `google` = the Google Cloud Translate target code (null for the source/default).
const LOCALES = [
  { code: 'en', label: 'English',    native: 'English',    dir: 'ltr', google: null },
  { code: 'ar', label: 'Arabic',     native: 'العربية',     dir: 'rtl', google: 'ar' },
  { code: 'zh', label: 'Chinese',    native: '繁體中文',     dir: 'ltr', google: 'zh-TW' },
  { code: 'de', label: 'German',     native: 'Deutsch',    dir: 'ltr', google: 'de' },
  { code: 'fr', label: 'French',     native: 'Français',   dir: 'ltr', google: 'fr' },
  { code: 'nl', label: 'Dutch',      native: 'Nederlands', dir: 'ltr', google: 'nl' },
  { code: 'es', label: 'Spanish',    native: 'Español',    dir: 'ltr', google: 'es' },
  { code: 'it', label: 'Italian',    native: 'Italiano',   dir: 'ltr', google: 'it' },
]

const CODES = LOCALES.map((l) => l.code)
const NON_DEFAULT = CODES.filter((c) => c !== 'en')
const byCode = (c) => LOCALES.find((l) => l.code === c) || LOCALES[0]
const dir = (c) => byCode(c).dir
const prefix = (c) => (c && c !== 'en' ? '/' + c : '')

